import json
with open('baseline-packages.json') as f: base = json.load(f)
with open('after-cpm-packages.json') as f: after = json.load(f)

def get_pkgs(data):
    result = {}
    for proj in data.get('projects', []):
        name = proj['path'].split('/')[-1]
        pkgs = {}
        for fw in proj.get('frameworks', []):
            for p in fw.get('topLevelPackages', []):
                pkgs[p['id']] = p.get('resolvedVersion', p.get('requestedVersion',''))
        result[name] = pkgs
    return result

b = get_pkgs(base)
a = get_pkgs(after)
changes = []
for proj in sorted(set(list(b.keys()) + list(a.keys()))):
    bp = b.get(proj, {})
    ap = a.get(proj, {})
    for pkg in sorted(set(list(bp.keys()) + list(ap.keys()))):
        bv = bp.get(pkg, 'N/A')
        av = ap.get(pkg, 'N/A')
        if bv != av:
            changes.append((proj, pkg, bv, av))

if changes:
    print('CHANGES:')
    for proj, pkg, bv, av in changes:
        print(f'  {proj}: {pkg} {bv} -> {av}')
else:
    print('No unexpected changes (aside from aligned versions)')
"

